@app.get("/questions/{test_id}")
async def get_questions(test_id: str):
    try:
        base_path = os.path.dirname(__file__)
        file_path = os.path.join(base_path, "data", f"{test_id}.json")
        print(f"Intentando abrir: {file_path}")
        if not os.path.exists(file_path):
            raise HTTPException(status_code=404, detail=f"Archivo no encontrado")
        with open(file_path, "r", encoding="utf-8") as f:
            return json.load(f)
            
    except Exception as e:
        print(f"Error crítico: {e}")
        raise HTTPException(status_code=500, detail=str(e))

@app.post("/calculate-nature")
async def calculate_nature(results: dict):
    scores = results.get("scores", {})
    gender = results.get("gender", "m")
    test_id = results.get("testId", "rescue")
    if not scores:
        return {"nature": "Desconocida", "pokemon": "MissingNo", "text": "..."}
    nature = max(scores, key=scores.get)
    game_data = POKEMAP.get(test_id, {})
    nature_info = game_data.get(nature, {})
    poke = nature_info.get(gender, "Pikachu")
    desc = nature_info.get("text", "Sos rarito dude")
    return {
        "nature": nature,
        "pokemon": poke,
        "text": desc,
        #"imageURL": f"https://play.pokemonshowdown.com/sprites/ani/{poke.lower()}.gif"
    }

